        <h1 id="introduction">Introduction</h1>
<aside>
    <strong>Base URL</strong>: <code>http://localhost</code>
</aside>
<pre><code>This documentation aims to provide all the information you need to work with our API.

&lt;aside&gt;As you scroll, you'll see code examples for working with the API in different programming languages in the dark area to the right (or as part of the content on mobile).
You can switch the language used with the tabs at the top right (or from the nav menu at the top left on mobile).&lt;/aside&gt;</code></pre>

        <h1 id="authenticating-requests">Authenticating requests</h1>
<p>This API is not authenticated.</p>

        <h1 id="endpoints">Endpoints</h1>

    

                                <h2 id="endpoints-POSTapi-pagamento-presencial">POST api/pagamento/presencial</h2>

<p>
</p>



<span id="example-requests-POSTapi-pagamento-presencial">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost/api/pagamento/presencial" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"aluno_id\": \"architecto\",
    \"professor_id\": \"architecto\",
    \"modalidade_id\": \"architecto\",
    \"data_aula\": \"2025-12-29\",
    \"hora_aula\": \"20:49\",
    \"valor_aula\": 39,
    \"status\": \"PENDING\",
    \"titulo\": \"z\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/pagamento/presencial"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "aluno_id": "architecto",
    "professor_id": "architecto",
    "modalidade_id": "architecto",
    "data_aula": "2025-12-29",
    "hora_aula": "20:49",
    "valor_aula": 39,
    "status": "PENDING",
    "titulo": "z"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

</span>

