    "province": "o",
    "postalCode": "qitpxnt",
    "personType": "JURIDICA",
    "name": "t"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

